#!/usr/bin/env python3
"""Vendor the CDN assets for grand-line (fonts + Tabler icons).

- Google Fonts woff2 for the four families used, latin subset only.
- Tabler icons-webfont 3.3.0 CSS + woff2/woff/ttf.
Run from the repo root:  python vendor/download_assets.py
"""
import os
import re
import urllib.request

UA = ("Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 "
      "(KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36")

ROOT = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
FONTS_DIR = os.path.join(ROOT, "vendor", "fonts")
TABLER_DIR = os.path.join(ROOT, "vendor", "tabler-icons")
TABLER_FONTS_DIR = os.path.join(TABLER_DIR, "fonts")

# (css2 query, key, is_variable, weight_descriptor_for_css)
FAMILIES = [
    ("Geist:wght@400;500;600;700", "geist", True, "100 900"),
    ("Instrument+Serif:ital@0;1", "instrument-serif", False, None),
    ("Special+Elite", "special-elite", False, None),
    ("Pirata+One", "pirata-one", False, None),
]

URL_RE = re.compile(r"url\((https://[^)]+\.woff2)\)")
FACE_RE = re.compile(r"/\*\s*([\w-]+)\s*\*/\s*(@font-face\s*\{[^}]*\})", re.S)


def get(url):
    req = urllib.request.Request(url, headers={"User-Agent": UA})
    with urllib.request.urlopen(req, timeout=60) as r:
        return r.read().decode("utf-8")


def get_bytes(url):
    req = urllib.request.Request(url, headers={"User-Agent": UA})
    with urllib.request.urlopen(req, timeout=60) as r:
        return r.read()


def main():
    os.makedirs(FONTS_DIR, exist_ok=True)
    os.makedirs(TABLER_FONTS_DIR, exist_ok=True)

    font_css_lines = []
    seen_face = set()  # dedupe identical @font-face blocks
    seen_variable = set()  # avoid re-downloading identical variable font
    for query, key, is_var, weight_desc in FAMILIES:
        css = get("https://fonts.googleapis.com/css2?family=" + query +
                  "&display=swap")
        for subset, block in FACE_RE.findall(css):
            if subset != "latin":
                continue
            fam = re.search(r"font-family:\s*'([^']+)'", block).group(1)
            style = re.search(r"font-style:\s*(\w+)", block).group(1)
            weight = re.search(r"font-weight:\s*(\d+)", block).group(1)
            url = URL_RE.search(block).group(1)

            if is_var:
                fname = f"{key}-variable.woff2"
                if fname not in seen_variable:
                    print(f"  font: {fam} (variable) -> {fname}")
                    with open(os.path.join(FONTS_DIR, fname), "wb") as f:
                        f.write(get_bytes(url))
                    seen_variable.add(fname)
                local_block = (
                    f"@font-face {{\n"
                    f"  font-family: '{fam}';\n"
                    f"  font-style: {style};\n"
                    f"  font-weight: {weight_desc};\n"
                    f"  font-display: swap;\n"
                    f"  src: url(./{fname}) format('woff2');\n}}\n"
                )
            else:
                fname = f"{key}-{weight}-{style}.woff2"
                print(f"  font: {fam} {weight} {style} -> {fname}")
                with open(os.path.join(FONTS_DIR, fname), "wb") as f:
                    f.write(get_bytes(url))
                local_block = block.replace(url, f"./{fname}")
            sig = (fam, style, local_block)
            if sig not in seen_face:
                seen_face.add(sig)
                font_css_lines.append(local_block)

    with open(os.path.join(FONTS_DIR, "fonts.css"), "w", encoding="utf-8") as f:
        f.write("/* Vendored Google Fonts — latin subset. Generated by download_assets.py */\n\n")
        f.write("\n".join(font_css_lines) + "\n")
    print("wrote vendor/fonts/fonts.css")

    # ---- Tabler icons ----
    css_url = ("https://cdn.jsdelivr.net/npm/@tabler/icons-webfont@3.3.0/"
               "dist/tabler-icons.min.css")
    tcss = get(css_url)
    refs = sorted(set(re.findall(r'url\(["\']?\.?/?fonts/([^)"\']+)', tcss)))
    for ref in refs:
        # ref like 'tabler-icons.woff2?v3.3.0' or 'tabler-icons.woff?'
        clean = ref.split("?")[0]
        src = ("https://cdn.jsdelivr.net/npm/@tabler/icons-webfont@3.3.0/"
               "dist/fonts/" + ref)
        data = get_bytes(src)
        with open(os.path.join(TABLER_FONTS_DIR, clean), "wb") as fo:
            fo.write(data)
        print(f"  icon font: {clean} ({len(data)} bytes)")
        tcss = tcss.replace(f"./fonts/{ref}", f"./fonts/{clean}")
        tcss = tcss.replace(f"fonts/{ref}", f"./fonts/{clean}")
    with open(os.path.join(TABLER_DIR, "tabler-icons.min.css"), "w",
              encoding="utf-8") as f:
        f.write(tcss)
    print("wrote vendor/tabler-icons/tabler-icons.min.css")
    print("DONE")


if __name__ == "__main__":
    main()
